#include <stdio.h>
#include <pthread.h>
int main(void) {
    pthread_attr_t attr;
    pthread_attr_init(&attr);
    int state;
    pthread_attr_getdetachstate(&attr, &state);
    printf("Default: %s\n", state == PTHREAD_CREATE_JOINABLE ? "JOINABLE" : "DETACHED");
    pthread_attr_setdetachstate(&attr, PTHREAD_CREATE_DETACHED);
    pthread_attr_getdetachstate(&attr, &state);
    printf("After set: %s\n", state == PTHREAD_CREATE_JOINABLE ? "JOINABLE" : "DETACHED");
    pthread_attr_destroy(&attr);
    return 0;
}

