    pthread_attr_t attr;
    pthread_attr_init(&attr);              // ★ initialiser les attributs
    int state;
    pthread_attr_getdetachstate(&attr, &state); // ★ lire l'état courant
    printf("Default: %s\n", state == PTHREAD_CREATE_JOINABLE ? "JOINABLE" : "DETACHED");
    pthread_attr_setdetachstate(&attr, PTHREAD_CREATE_DETACHED); // ★ changer
    pthread_attr_getdetachstate(&attr, &state);
    printf("After set: %s\n", state == PTHREAD_CREATE_JOINABLE ? "JOINABLE" : "DETACHED");
    pthread_attr_destroy(&attr);           // ★ libérer les attributs
    return 0;
}

